                    continue
                cols.add(c); d.add(r - c); a.add(r + c)
                t += place(r + 1)
                cols.remove(c); d.remove(r - c); a.remove(r + c)
            return t
        return place(0)
    seen = set()
    for board in output:
        if not isinstance(board, list) or len(board) != n:
            return False
        queens = []
        for row in board:
            if not isinstance(row, str) or len(row) != n:
                return False
            if row.count('Q') != 1:
                return False
            if any(ch not in 'Q.' for ch in row):
                return False
            queens.append(row.index('Q'))
        ok = True
        for i in range(n):
            for j in range(i + 1, n):
                if queens[i] == queens[j] or abs(queens[i] - queens[j]) == j - i:
