function validate(args, output) {
    const n = args[0];
    if (!Array.isArray(output)) return false;
    function totalCount(n) {
        const cols = new Set(), d = new Set(), a = new Set();
        function place(r) {
            if (r === n) return 1;
            let t = 0;
            for (let c = 0; c < n; c++) {
                if (cols.has(c) || d.has(r - c) || a.has(r + c)) continue;
                cols.add(c); d.add(r - c); a.add(r + c);
                t += place(r + 1);
                cols.delete(c); d.delete(r - c); a.delete(r + c);
            }
            return t;
        }
        return place(0);
    }
    const seen = new Set();
    for (const board of output) {
        if (!Array.isArray(board) || board.length !== n) return false;
        const queens = [];
        for (const row of board) {
            if (typeof row !== 'string' || row.length !== n) return false;
            let cnt = 0, pos = -1;
            for (let k = 0; k < row.length; k++) {
                if (row[k] === 'Q') { cnt++; pos = k; }
                else if (row[k] !== '.') return false;
            }
            if (cnt !== 1) return false;
            queens.push(pos);
        }
        let ok = true;
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                if (queens[i] === queens[j] || Math.abs(queens[i] - queens[j]) === j - i) ok = false;
            }
        }
        if (!ok) return false;
        const key = queens.join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    return seen.size === totalCount(n);
}

