class Solution:
    def solveNQueens(self, n):
        from itertools import permutations
        sols = []
        for perm in permutations(range(n)):
            ok = True
            for i in range(n):
                for j in range(i + 1, n):
                    if abs(perm[i] - perm[j]) == j - i:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                sols.append(perm)
        sols.sort()
        boards = []
        for perm in sols:
            boards.append(['.' * col + 'Q' + '.' * (n - col - 1) for col in perm])
        return boards

