class Solution:
    def solveNQueens(self, n):
        sols = []
        cols = set(); diag = set(); anti = set()
        placement = []
        def place(row):
            if row == n:
                sols.append(tuple(placement))
                return
            for c in range(n):
                if c in cols or (row - c) in diag or (row + c) in anti:
                    continue
                cols.add(c); diag.add(row - c); anti.add(row + c)
                placement.append(c)
                place(row + 1)
                placement.pop()
                cols.remove(c); diag.remove(row - c); anti.remove(row + c)
        place(0)
        sols.sort()
        return [['.' * c + 'Q' + '.' * (n - c - 1) for c in perm] for perm in sols]

