var solveNQueens = function(n) {
    const sols = [];
    const cols = new Set(), diag = new Set(), anti = new Set();
    const placement = [];
    function place(row) {
        if (row === n) {
            sols.push(placement.slice());
            return;
        }
        for (let c = 0; c < n; c++) {
            if (cols.has(c) || diag.has(row - c) || anti.has(row + c)) continue;
            cols.add(c); diag.add(row - c); anti.add(row + c);
            placement.push(c);
            place(row + 1);
            placement.pop();
            cols.delete(c); diag.delete(row - c); anti.delete(row + c);
        }
    }
    place(0);
    sols.sort((a, b) => {
        for (let i = 0; i < n; i++) if (a[i] !== b[i]) return a[i] - b[i];
        return 0;
    });
    return sols.map(perm => perm.map(c => '.'.repeat(c) + 'Q' + '.'.repeat(n - c - 1)));
};
